const AWS = require('aws-sdk');
const dynamodb = new AWS.DynamoDB.DocumentClient({ region: 'your-region' });
const sqs = new AWS.SQS({ region: 'your-region' });

exports.handler = async (event) => {
  try {
    const order = JSON.parse(event.Records[0].body);
    console.log('Processing order:', order);

    // Call external payment API
    const paymentResponse = await callPaymentAPI(order);
    if (!paymentResponse.success) {
      throw new Error(`Payment failed: ${paymentResponse.error}`);
    }

    // Update DynamoDB with order status
    const updateParams = {
      TableName: 'orders-table',
      Key: { id: order.id },
      UpdateExpression: 'set #status = :status',
      ExpressionAttributeNames: { '#status': 'status' },
      ExpressionAttributeValues: { ':status': paymentResponse.status }
    };
    await dynamodb.update(updateParams).promise();

    console.log('Order processed successfully:', order);
  } catch (error) {
    console.error('Error processing order:', error);
  }

  return {};
};

async function callPaymentAPI(order) {
  try {
    const response = await fetch(`https://payment-api.com/charge`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ amount: order.amount, currency: order.currency })
    });
    const data = await response.json();
    return { success: true, status: data.status };
  } catch (error) {
    console.error('Error calling payment API:', error);
    return { success: false, error: 'Payment failed' };
  }
}